        ConsoleFormatter.PrintReportCard(card);
    }

    // Save this run to history
    historyService.SaveAuditResult(report);

    return 0;
}
// 📉 Burndown ──────────────────────────────────────────────────────

static int HandleBurndown(CliOptions options)
{
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.BurndownDays);

    if (runs.Count < 2)
    {
        ConsoleFormatter.PrintWarning("Need at least 2 audit runs for burndown. Run --score or --audit first.");
        return 1;
    }

    var dataPoints = runs
        .OrderBy(r => r.Timestamp)
        .Select(r =>
        {
            var findings = r.Findings ?? [];
            var total = findings.Count;
            var critical = findings.Count(f => string.Equals(f.Severity, "Critical", StringComparison.OrdinalIgnoreCase));
            var high = findings.Count(f => string.Equals(f.Severity, "High", StringComparison.OrdinalIgnoreCase));
            var medium = findings.Count(f => string.Equals(f.Severity, "Medium", StringComparison.OrdinalIgnoreCase));
            var low = findings.Count(f => string.Equals(f.Severity, "Low", StringComparison.OrdinalIgnoreCase));
            return (date: r.Timestamp, total, critical, high, medium, low);
        })
        .ToList();

    var filteredCounts = dataPoints
        .Select(p => GetBurndownFilteredCount(p, options.BurndownSeverityFilter))
        .ToList();

    var earliest = dataPoints[0].date;
    var xs = dataPoints.Select(p => (p.date - earliest).TotalDays).ToArray();
    var ys = filteredCounts.Select(c => (double)c).ToArray();

    // Linear regression
    static (double slope, double intercept, double r2) LinReg(double[] x, double[] y)
    {
        int n = x.Length;
        double sumX = x.Sum(), sumY = y.Sum();
        double sumXY = x.Zip(y, (a, b) => a * b).Sum();
        double sumX2 = x.Sum(a => a * a);
        double denom = n * sumX2 - sumX * sumX;
        if (Math.Abs(denom) < 1e-10)
            return (0, sumY / n, 0);
        double slope = (n * sumXY - sumX * sumY) / denom;
        double intercept = (sumY - slope * sumX) / n;
        double ssRes = x.Zip(y, (xi, yi) => Math.Pow(yi - (slope * xi + intercept), 2)).Sum();
        double meanY = sumY / n;
        double ssTot = y.Sum(yi => Math.Pow(yi - meanY, 2));
        double r2 = ssTot > 0 ? 1 - ssRes / ssTot : 0;
        return (slope, intercept, r2);
    }

    var (slope, intercept, _) = LinReg(xs, ys);

    DateTimeOffset? projectedZero = null;
    if (slope < 0 && intercept > 0)
    {
        var daysToZero = -intercept / slope;
        projectedZero = earliest.AddDays(daysToZero);
        if (projectedZero < DateTimeOffset.UtcNow)
            projectedZero = null;
    }

    if (options.Json)
    {
        var result = new
        {
            historyDays = options.BurndownDays,
            dataPoints = dataPoints.Select(p => new
            {
                date = p.date.ToString("yyyy-MM-dd"),
                total = p.total,
                critical = p.critical,
                high = p.high,
                medium = p.medium,
                low = p.low
            }),
            burnRate = Math.Round(slope, 4),
            projectedZeroDate = projectedZero?.ToString("yyyy-MM-dd"),
            severityFilter = options.BurndownSeverityFilter ?? "all"
        };
        var jsonOptions = new JsonSerializerOptions
        {
            WriteIndented = true,
            Converters = { new JsonStringEnumConverter() }
        };
        var json = JsonSerializer.Serialize(result, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else
    {
        ConsoleFormatter.PrintBurndown(
            options.BurndownDays,
            dataPoints,
            options.BurndownWidth,
            options.BurndownSeverityFilter,
            projectedZero,
            slope);
    }

    return 0;
}

static int GetBurndownFilteredCount(
    (DateTimeOffset date, int total, int critical, int high, int medium, int low) point,
    string? severityFilter)
{
    return severityFilter switch
    {
        "critical" => point.critical,
        "high" => point.high,
        "medium" => point.medium,
        "low" => point.low,
        _ => point.total
    };
}

// ── Security Changelog ───────────────────────────────────────────

static int HandleChangelog(CliOptions options)
{
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.ChangelogDays);

    if (runs.Count < 2)
    {
        ConsoleFormatter.PrintWarning("Need at least 2 audit runs for changelog. Run --score or --audit first.");
        return 1;
    }

    var ordered = runs.OrderBy(r => r.Timestamp).ToList();

    // Group runs into periods (week or month)
    var periods = new List<ChangelogPeriod>();
    var groupedRuns = options.ChangelogGroupBy switch
    {
        "month" => ordered.GroupBy(r => new { r.Timestamp.Year, r.Timestamp.Month })
            .Select(g => (
                label: $"{g.First().Timestamp:yyyy-MM}",
                runs: g.ToList()
            )),
        "day" => ordered.GroupBy(r => r.Timestamp.Date)
            .Select(g => (
                label: $"{g.First().Timestamp:yyyy-MM-dd}",
                runs: g.ToList()
            )),
        _ => ordered.GroupBy(r =>
            {
                var cal = System.Globalization.CultureInfo.InvariantCulture.Calendar;
                var week = cal.GetWeekOfYear(r.Timestamp.DateTime, System.Globalization.CalendarWeekRule.FirstDay, DayOfWeek.Monday);
                return new { r.Timestamp.Year, Week = week };
            })
            .Select(g => (
                label: $"Week of {g.First().Timestamp:yyyy-MM-dd}",
                runs: g.ToList()
            ))
    };

    var totalNew = 0;
    var totalResolved = 0;
    var moduleNewCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
    var moduleResolvedCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

    // For each period, compare first vs last run to find new/resolved findings
    AuditRunRecord? previousPeriodLast = null;

    foreach (var (label, periodRuns) in groupedRuns)
    {
        var first = periodRuns.First();
        var last = periodRuns.Last();

        // Compare against end of previous period (or first run of this period)
        var baseline = previousPeriodLast ?? first;
        var current = last;

        var baselineFindings = new HashSet<string>(
            (baseline.Findings ?? []).Select(f => $"{f.ModuleName}::{f.Title}"),
            StringComparer.OrdinalIgnoreCase);

        var currentFindings = new HashSet<string>(
            (current.Findings ?? []).Select(f => $"{f.ModuleName}::{f.Title}"),
            StringComparer.OrdinalIgnoreCase);

        var newKeys = currentFindings.Except(baselineFindings).ToList();
        var resolvedKeys = baselineFindings.Except(currentFindings).ToList();

        var currentFindingsLookup = (current.Findings ?? [])
            .GroupBy(f => $"{f.ModuleName}::{f.Title}", StringComparer.OrdinalIgnoreCase)
            .ToDictionary(g => g.Key, g => g.First(), StringComparer.OrdinalIgnoreCase);

        var baselineFindingsLookup = (baseline.Findings ?? [])
            .GroupBy(f => $"{f.ModuleName}::{f.Title}", StringComparer.OrdinalIgnoreCase)
            .ToDictionary(g => g.Key, g => g.First(), StringComparer.OrdinalIgnoreCase);

        var period = new ChangelogPeriod
        {
            Label = label,
            AuditCount = periodRuns.Count,
            StartScore = baseline.OverallScore,
            EndScore = current.OverallScore,
            NewFindings = newKeys
                .Where(k => currentFindingsLookup.ContainsKey(k))
                .Select(k => {
                    var f = currentFindingsLookup[k];
                    return new ChangelogFinding { Title = f.Title, Severity = f.Severity, Module = f.ModuleName };
                })
                .OrderByDescending(f => SeverityRank(f.Severity))
                .ToList(),
            ResolvedFindings = resolvedKeys
                .Where(k => baselineFindingsLookup.ContainsKey(k))
                .Select(k => {
                    var f = baselineFindingsLookup[k];
                    return new ChangelogFinding { Title = f.Title, Severity = f.Severity, Module = f.ModuleName };
                })
                .OrderByDescending(f => SeverityRank(f.Severity))
                .ToList()
        };

        // Track module impact
        foreach (var f in period.NewFindings)
        {
            moduleNewCounts.TryGetValue(f.Module, out var c);
            moduleNewCounts[f.Module] = c + 1;
        }
        foreach (var f in period.ResolvedFindings)
        {
            moduleResolvedCounts.TryGetValue(f.Module, out var c);
            moduleResolvedCounts[f.Module] = c + 1;
        }

        totalNew += period.NewFindings.Count;
        totalResolved += period.ResolvedFindings.Count;

        // Only add periods with changes (or if it's the only period)
        if (period.NewFindings.Count > 0 || period.ResolvedFindings.Count > 0)
            periods.Add(period);

        previousPeriodLast = last;
    }

    // Build module impact
    var allModules = moduleNewCounts.Keys.Union(moduleResolvedCounts.Keys, StringComparer.OrdinalIgnoreCase);
    var moduleImpact = allModules.Select(m => new ModuleImpactEntry
    {
        Module = m,
        NewCount = moduleNewCounts.GetValueOrDefault(m),
        ResolvedCount = moduleResolvedCounts.GetValueOrDefault(m)
    }).Where(e => e.NewCount > 0 || e.ResolvedCount > 0).ToList();

    var report = new ChangelogReport
    {
        StartDate = ordered.First().Timestamp,
        EndDate = ordered.Last().Timestamp,
        TotalDays = options.ChangelogDays,
        TotalAudits = ordered.Count,
        StartScore = ordered.First().OverallScore,
        EndScore = ordered.Last().OverallScore,
        TotalNew = totalNew,
        TotalResolved = totalResolved,
        Periods = periods,
        ModuleImpact = moduleImpact
    };

    if (options.Json)
    {
        var jsonOptions = new JsonSerializerOptions
        {
            WriteIndented = true,
            Converters = { new JsonStringEnumConverter() }
        };
        var json = JsonSerializer.Serialize(report, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else
    {
        ConsoleFormatter.PrintChangelog(report);
    }

    return 0;

    static int SeverityRank(string severity) => severity.ToLowerInvariant() switch
    {
        "critical" => 3,
        "warning" => 2,
        "info" => 1,
        _ => 0
    };
}

// ── Security Pulse ──────────────────────────────────────────────────

static int HandlePulse(CliOptions options)
{
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.PulseDays);

    if (runs.Count < 2)
    {
        ConsoleFormatter.PrintWarning("Need at least 2 audit runs for pulse. Run --score or --audit first.");
        return 1;
    }

    var dataPoints = runs
        .OrderBy(r => r.Timestamp)
        .Select(r =>
        {
            var findings = r.Findings ?? [];
            var critical = findings.Count(f => string.Equals(f.Severity, "Critical", StringComparison.OrdinalIgnoreCase));
            var high = findings.Count(f => string.Equals(f.Severity, "High", StringComparison.OrdinalIgnoreCase));
            var medium = findings.Count(f => string.Equals(f.Severity, "Medium", StringComparison.OrdinalIgnoreCase));
            var low = findings.Count(f => string.Equals(f.Severity, "Low", StringComparison.OrdinalIgnoreCase));
            return (date: r.Timestamp, score: r.OverallScore, total: findings.Count, critical, high, medium, low);
        })
        .ToList();

    if (options.Json)
    {
        var report = new
        {
            command = "pulse",
            period = new { days = options.PulseDays, from = dataPoints[0].date, to = dataPoints[^1].date },
            alertThreshold = options.PulseAlertBelow,
            points = dataPoints.Select(p => new
            {
                date = p.date,
                score = p.score,
                findings = p.total,
                critical = p.critical,
                high = p.high,
                medium = p.medium,
                low = p.low
            })
        };
        var jsonOptions = new JsonSerializerOptions
        {
            WriteIndented = true,
            Converters = { new JsonStringEnumConverter() }
        };
        var json = JsonSerializer.Serialize(report, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else
    {
        ConsoleFormatter.PrintPulse(dataPoints, options.PulseWidth, options.PulseAlertBelow, options.PulseShowFindings);
    }

    return 0;
}

// ── Security Calendar ────────────────────────────────────────────────

static int HandleCalendar(CliOptions options)
{
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.CalendarDays);
    var ordered = runs.OrderBy(r => r.Timestamp).ToList();
    var now = DateTimeOffset.Now;
    var forecastEnd = now.AddDays(options.CalendarForecastDays);

    var intervals = new List<double>();
    for (int idx = 1; idx < ordered.Count; idx++)
        intervals.Add((ordered[idx].Timestamp - ordered[idx - 1].Timestamp).TotalDays);
    var avgInterval = intervals.Count > 0 ? intervals.Average() : 7.0;
    var recommendedInterval = Math.Max(1, Math.Round(avgInterval));

    var latestRun = ordered.LastOrDefault();
    var criticalFindings = (latestRun?.Findings ?? [])
        .Where(f => f.Severity is "Critical" or "High")
        .ToList();

    var events = new List<CalendarEvent>();

    if (options.CalendarIncludeAudits)
    {
        var nextAudit = now.AddDays(recommendedInterval);
        var auditNum = 1;
        while (nextAudit <= forecastEnd)
        {
            events.Add(new CalendarEvent
            {
                Title = $"Scheduled Security Audit #{auditNum}",
                Start = nextAudit,
                Duration = TimeSpan.FromMinutes(30),
                Description = $"Regular WinSentinel audit (every {recommendedInterval} days based on history)",
                Category = "Audit",
                Priority = "Normal"
            });
            nextAudit = nextAudit.AddDays(recommendedInterval);
            auditNum++;
        }
    }

    if (options.CalendarIncludeSla && criticalFindings.Count > 0)
    {
        foreach (var finding in criticalFindings)
        {
            var slaDays = finding.Severity == "Critical" ? 3 : 14;
            var deadline = now.AddDays(slaDays);
            if (deadline <= forecastEnd)
            {
                events.Add(new CalendarEvent
                {
                    Title = $"SLA Deadline: {CalTruncate(finding.Title, 50)}",
                    Start = deadline,
                    Duration = TimeSpan.FromMinutes(15),
                    Description = $"[{finding.Severity}] {finding.Title}\nModule: {finding.ModuleName}\n\nRemediation: {finding.Remediation ?? "See audit details"}",
                    Category = "SLA",
                    Priority = finding.Severity == "Critical" ? "High" : "Normal"
                });

                if (slaDays > 1)
                {
                    events.Add(new CalendarEvent
                    {
                        Title = $"SLA Warning: {CalTruncate(finding.Title, 50)} (due tomorrow)",
                        Start = deadline.AddDays(-1),
                        Duration = TimeSpan.FromMinutes(10),
                        Description = $"Reminder: {finding.Severity} finding due tomorrow.\n{finding.Title}",
                        Category = "SLA Reminder",
                        Priority = "High"
                    });
                }
            }
        }
    }

    if (options.CalendarIncludeReviews)
    {
        var nextSunday = now.AddDays(((int)DayOfWeek.Sunday - (int)now.DayOfWeek + 7) % 7);
        if (nextSunday == now) nextSunday = nextSunday.AddDays(7);
        while (nextSunday <= forecastEnd)
        {
            events.Add(new CalendarEvent
            {
                Title = "Weekly Security Review",
                Start = nextSunday.Date.AddHours(10),
                Duration = TimeSpan.FromMinutes(30),
                Description = "Review WinSentinel trends, check for regressions, plan remediation.\nRun: winsentinel --reportcard",
                Category = "Review",
                Priority = "Normal"
            });
            nextSunday = nextSunday.AddDays(7);
        }

        var nextMonth = new DateTimeOffset(now.Year, now.Month, 1, 14, 0, 0, now.Offset).AddMonths(1);
        while (nextMonth <= forecastEnd)
        {
            events.Add(new CalendarEvent
            {
                Title = "Monthly Security Deep Review",
                Start = nextMonth,
                Duration = TimeSpan.FromHours(1),
                Description = "Comprehensive review: compliance, maturity, baseline.\nRun: winsentinel --compliance\nRun: winsentinel --maturity\nRun: winsentinel --baseline save monthly",
                Category = "Review",
                Priority = "Normal"
            });
            nextMonth = nextMonth.AddMonths(1);
        }
    }

    events = events.OrderBy(e => e.Start).ToList();

    if (options.Json)
    {
        var report = new
        {
            generated = now,
            historyDays = options.CalendarDays,
            forecastDays = options.CalendarForecastDays,
            auditHistory = new
            {
                totalRuns = ordered.Count,
                averageIntervalDays = Math.Round(avgInterval, 1),
                recommendedIntervalDays = recommendedInterval,
                latestScore = latestRun?.OverallScore ?? 0
            },
            events = events.Select(e => new
            {
                title = e.Title,
                start = e.Start,
                durationMinutes = e.Duration.TotalMinutes,
                description = e.Description,
                category = e.Category,
                priority = e.Priority
            })
        };
        var jsonOptions = new JsonSerializerOptions { WriteIndented = true, Converters = { new JsonStringEnumConverter() } };
        var json = JsonSerializer.Serialize(report, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else if (options.CalendarFormat == "ics")
    {
        var ics = GenerateIcs(events, now);
        var outputFile = options.OutputFile ?? "winsentinel-calendar.ics";
        WriteOutput(ics, outputFile);
        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine($"  Calendar exported to: {outputFile}");
        Console.ResetColor();
        Console.WriteLine($"     {events.Count} events generated for next {options.CalendarForecastDays} days");
        Console.WriteLine($"     Import into Outlook, Google Calendar, or Apple Calendar");
        Console.WriteLine();
    }
    else
    {
        ConsoleFormatter.PrintCalendar(events, ordered.Count, avgInterval, recommendedInterval,
            latestRun?.OverallScore ?? 0, criticalFindings.Count, options.CalendarForecastDays);
    }

    return 0;
}

static string GenerateIcs(List<CalendarEvent> events, DateTimeOffset now)
{
    var sb = new System.Text.StringBuilder();
    sb.AppendLine("BEGIN:VCALENDAR");
    sb.AppendLine("VERSION:2.0");
    sb.AppendLine("PRODID:-//WinSentinel//Security Calendar//EN");
    sb.AppendLine("CALSCALE:GREGORIAN");
    sb.AppendLine("METHOD:PUBLISH");
    sb.AppendLine("X-WR-CALNAME:WinSentinel Security");

    foreach (var evt in events)
    {
        sb.AppendLine("BEGIN:VEVENT");
        sb.AppendLine($"UID:{Guid.NewGuid()}@winsentinel");
        sb.AppendLine($"DTSTAMP:{now.UtcDateTime:yyyyMMdd'T'HHmmss'Z'}");
        sb.AppendLine($"DTSTART:{evt.Start.UtcDateTime:yyyyMMdd'T'HHmmss'Z'}");
        sb.AppendLine($"DTEND:{evt.Start.Add(evt.Duration).UtcDateTime:yyyyMMdd'T'HHmmss'Z'}");
        sb.AppendLine($"SUMMARY:{EscapeIcs(evt.Title)}");
        sb.AppendLine($"DESCRIPTION:{EscapeIcs(evt.Description)}");
        sb.AppendLine($"CATEGORIES:{evt.Category}");
        if (evt.Priority == "High")
            sb.AppendLine("PRIORITY:1");
        if (evt.Category is "SLA" or "SLA Reminder")
        {
            sb.AppendLine("BEGIN:VALARM");
            sb.AppendLine("TRIGGER:-PT15M");
            sb.AppendLine("ACTION:DISPLAY");
            sb.AppendLine($"DESCRIPTION:Reminder: {EscapeIcs(evt.Title)}");
            sb.AppendLine("END:VALARM");
        }
        sb.AppendLine("END:VEVENT");
    }

    sb.AppendLine("END:VCALENDAR");
    return sb.ToString();
}

static string EscapeIcs(string text) =>
    text.Replace("\\", "\\\\").Replace("\n", "\\n").Replace(",", "\\,").Replace(";", "\\;");

static string CalTruncate(string text, int maxLength) =>
    text.Length <= maxLength ? text : text[..(maxLength - 3)] + "...";

// 💳 Security Debt Calculator

static async Task<int> HandleDebt(CliOptions options)
{
    var (report, _, elapsed) = await RunAuditAsync(options, suppressOutput: options.Quiet,
        bannerMessage: "Running audit for security debt analysis...");

    // Collect all non-pass findings
    var allFindings = report.Results
        .SelectMany(r => r.Findings.Where(f => f.Severity != Severity.Pass)
            .Select(f => (Module: r.ModuleName, Finding: f)))
        .ToList();

    // Apply severity filter
    if (!string.IsNullOrEmpty(options.DebtSeverityFilter))
    {
        if (Enum.TryParse<Severity>(options.DebtSeverityFilter, true, out var sevFilter))
        {
            allFindings = allFindings.Where(f => f.Finding.Severity == sevFilter).ToList();
        }
    }

    // Apply module filter
    if (!string.IsNullOrEmpty(options.DebtModuleFilter))
    {
        allFindings = allFindings
            .Where(f => f.Module.Contains(options.DebtModuleFilter, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    // Estimate remediation effort per finding
    var debtItems = allFindings.Select(f =>
    {
        // Estimate hours based on severity and whether auto-fixable
        bool fixable = !string.IsNullOrEmpty(f.Finding.FixCommand);
        double baseHours = f.Finding.Severity switch
        {
            Severity.Critical => fixable ? 0.25 : 4.0,
            Severity.Warning => fixable ? 0.15 : 2.0,
            Severity.Info => fixable ? 0.1 : 0.5,
            _ => 0.25
        };

        // Boost estimate if remediation text is long (suggests complexity)
        if (!string.IsNullOrEmpty(f.Finding.Remediation) && f.Finding.Remediation.Length > 200)
            baseHours *= 1.5;

        // ROI = severity_weight / effort  (higher = better payoff per hour)
        double sevWeight = f.Finding.Severity switch
        {
            Severity.Critical => 10.0,
            Severity.Warning => 5.0,
            Severity.Info => 1.0,
            _ => 0.5
        };
        double roi = baseHours > 0 ? sevWeight / baseHours : 0;
        if (fixable) roi *= 2; // auto-fixable items are higher ROI

        return new DebtItem
        {
            Module = f.Module,
            Title = f.Finding.Title ?? "(untitled)",
            Severity = f.Finding.Severity.ToString(),
            EstimatedHours = baseHours,
            RoiScore = roi,
            IsFixable = fixable,
            Remediation = f.Finding.Remediation
        };
    }).ToList();

    // Sort
    debtItems = options.DebtSortBy.ToLowerInvariant() switch
    {
        "effort" or "hours" => debtItems.OrderByDescending(d => d.EstimatedHours).ToList(),
        "severity" => debtItems.OrderByDescending(d => d.Severity == "Critical" ? 3 : d.Severity == "Warning" ? 2 : 1)
            .ThenByDescending(d => d.RoiScore).ToList(),
        _ => debtItems.OrderByDescending(d => d.RoiScore).ToList() // default: roi
    };

    var totalDebt = debtItems.Sum(d => d.EstimatedHours);

    var moduleBreakdown = debtItems
        .GroupBy(d => d.Module)
        .Select(g => (Module: g.Key, Hours: g.Sum(d => d.EstimatedHours), Count: g.Count()))
        .OrderByDescending(m => m.Hours)
        .ToList();

    var severityBreakdown = debtItems
        .GroupBy(d => d.Severity)
        .Select(g => (Severity: g.Key, Hours: g.Sum(d => d.EstimatedHours), Count: g.Count()))
        .OrderByDescending(s => s.Severity == "Critical" ? 3 : s.Severity == "Warning" ? 2 : 1)
        .ToList();

    var displayItems = debtItems.Take(options.DebtTop).ToList();

    if (options.Json)
    {
        var jsonOptions = new JsonSerializerOptions { WriteIndented = true, Converters = { new JsonStringEnumConverter() } };
        var output = new
        {
            generatedAt = DateTimeOffset.UtcNow,
            elapsed = elapsed.TotalSeconds,
            totalFindings = allFindings.Count,
            totalDebtHours = totalDebt,
            debtLevel = totalDebt > 80 ? "CRITICAL" : totalDebt > 40 ? "HIGH" : totalDebt > 10 ? "MODERATE" : "LOW",
            sortedBy = options.DebtSortBy,
            severityBreakdown = severityBreakdown.Select(s => new { severity = s.Severity, hours = s.Hours, count = s.Count }),
            moduleBreakdown = moduleBreakdown.Select(m => new { module = m.Module, hours = m.Hours, count = m.Count }),
            items = displayItems.Select(d => new
            {
                module = d.Module,
                title = d.Title,
                severity = d.Severity,
                estimatedHours = d.EstimatedHours,
                roiScore = d.RoiScore,
                isFixable = d.IsFixable,
                remediation = d.Remediation
            }),
            quickWins = debtItems.Where(i => i.EstimatedHours <= 0.5 && i.RoiScore >= 5).Count()
        };
        WriteOutput(JsonSerializer.Serialize(output, jsonOptions), options.OutputFile);
        return 0;
    }

    ConsoleFormatter.PrintDebt(displayItems, allFindings.Count, totalDebt,
        moduleBreakdown, severityBreakdown, options.DebtSortBy, elapsed);
    return 0;
}

// ── Anomaly Watchdog ─────────────────────────────────────────────

static int HandleWatchdog(CliOptions options)
{
    ConsoleFormatter.PrintBanner();

    using var historyService = new AuditHistoryService();
    historyService.EnsureDatabase();

    var runs = historyService.GetHistory(options.WatchdogDays);

    if (runs.Count < 2)
    {
        if (options.Json)
        {
            WriteOutput("{\"error\": \"Need at least 2 audit runs for anomaly detection.\"}", options.OutputFile);
        }
        else if (!options.Quiet)
        {
            Console.WriteLine();
            ConsoleFormatter.PrintError("Need at least 2 audit runs for anomaly detection. Run more audits!");
        }
        return 1;
    }

    var service = new AnomalyWatchdogService(options.WatchdogWarnZ, options.WatchdogCritZ);
    var report = service.Analyze(runs, options.WatchdogDays);

    if (options.Json)
    {
        var jsonOptions = new JsonSerializerOptions { WriteIndented = true, Converters = { new JsonStringEnumConverter() } };
        Console.WriteLine(JsonSerializer.Serialize(report, jsonOptions));
        return 0;
    }

    ConsoleFormatter.PrintWatchdog(report);
    return 0;
}

// ── Security Patrol ──────────────────────────────────────────────────

static async Task<int> HandlePatrol(CliOptions options)
{
    await Task.CompletedTask; // satisfy async signature
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.PatrolDays);
    var ordered = runs.OrderBy(r => r.Timestamp).ToList();

    var report = new PatrolReport
    {
        LookbackDays = options.PatrolDays,
        RunsAnalyzed = ordered.Count
    };

    if (ordered.Count == 0)
    {
        ConsoleFormatter.PrintWarning("No audit history found. Run 'winsentinel --audit' first, then patrol.");
        return 1;
    }

    var latest = ordered.Last();
    var latestFindings = latest.Findings ?? [];

    // ── Checkpoint 1: Score Health ──
    {
        var cp = new PatrolCheckpoint { Name = "Score Health" };
        var score = latest.OverallScore;
        if (score >= 80)
        {
            cp.Status = PatrolStatus.Pass;
            cp.Summary = $"Current score: {score}/100 — healthy";
        }
        else if (score >= 50)
        {
            cp.Status = PatrolStatus.Warn;
            cp.Summary = $"Current score: {score}/100 — below target";
            report.RecommendedActions.Add(new PatrolAction
            {
                Priority = "medium",
                Description = "Score is below 80. Review findings and remediate high-severity issues.",
                Command = "winsentinel --audit"
            });
        }
        else
        {
            cp.Status = PatrolStatus.Fail;
            cp.Summary = $"Current score: {score}/100 — critical";
            report.RecommendedActions.Add(new PatrolAction
            {
                Priority = "high",
                Description = "Score is critically low. Immediate remediation required.",
                Command = "winsentinel --fixall"
            });
        }

        if (ordered.Count >= 2)
        {
            var prev = ordered[^2].OverallScore;
            var delta = score - prev;
            var trend = delta > 0 ? $"+{delta}" : delta.ToString();
            cp.Details.Add($"Trend: {trend} since last audit");
        }
        report.Checkpoints.Add(cp);
    }

    // ── Checkpoint 2: Critical & High Findings ──
    {
        var cp = new PatrolCheckpoint { Name = "Critical Exposure" };
        var criticals = latestFindings.Count(f => string.Equals(f.Severity, "Critical", StringComparison.OrdinalIgnoreCase));
        var highs = latestFindings.Count(f => string.Equals(f.Severity, "High", StringComparison.OrdinalIgnoreCase));
        var total = criticals + highs;

        if (total == 0)
        {
            cp.Status = PatrolStatus.Pass;
            cp.Summary = "No critical or high severity findings";
        }
        else if (criticals == 0)
        {
            cp.Status = PatrolStatus.Warn;
            cp.Summary = $"{highs} high severity finding(s), 0 critical";
            cp.Details.AddRange(latestFindings
                .Where(f => string.Equals(f.Severity, "High", StringComparison.OrdinalIgnoreCase))
                .Take(3)
                .Select(f => f.Title));
            report.RecommendedActions.Add(new PatrolAction
            {
                Priority = "medium",
                Description = $"Address {highs} high-severity finding(s)",
                Command = "winsentinel --triage"
            });
        }
        else
        {
            cp.Status = PatrolStatus.Fail;
            cp.Summary = $"{criticals} critical + {highs} high severity finding(s)";
            cp.Details.AddRange(latestFindings
                .Where(f => string.Equals(f.Severity, "Critical", StringComparison.OrdinalIgnoreCase))
                .Take(3)
                .Select(f => f.Title));
            report.RecommendedActions.Add(new PatrolAction
            {
                Priority = "high",
                Description = $"Remediate {criticals} critical finding(s) immediately",
                Command = "winsentinel --fixall"
            });
        }
        report.Checkpoints.Add(cp);
    }

    // ── Checkpoint 3: Finding Velocity ──
    {
        var cp = new PatrolCheckpoint { Name = "Finding Velocity" };
        if (ordered.Count >= 3)
        {
            var recentCounts = ordered.TakeLast(5).Select(r => (r.Findings ?? []).Count).ToList();
            var first = recentCounts.First();
            var last = recentCounts.Last();
            var avgChange = (double)(last - first) / Math.Max(recentCounts.Count - 1, 1);

            if (avgChange <= 0)
            {
                cp.Status = PatrolStatus.Pass;
                cp.Summary = $"Findings trending down (avg {avgChange:+0.0;-0.0;0} per run)";
            }
            else if (avgChange <= 2)
            {
                cp.Status = PatrolStatus.Warn;
                cp.Summary = $"Findings slowly increasing (avg +{avgChange:0.0} per run)";
            }
            else
            {
                cp.Status = PatrolStatus.Fail;
                cp.Summary = $"Findings growing fast (avg +{avgChange:0.0} per run)";
                report.RecommendedActions.Add(new PatrolAction
                {
                    Priority = "high",
                    Description = "Finding count is accelerating. Review recent changes.",
                    Command = "winsentinel --changelog"
                });
            }
            cp.Details.Add($"Recent counts: {string.Join(" → ", recentCounts)}");
        }
        else
        {
            cp.Status = PatrolStatus.Skip;
            cp.Summary = "Not enough history for velocity analysis (need 3+ runs)";
        }
        report.Checkpoints.Add(cp);
    }

    // ── Checkpoint 4: Module Coverage ──
    {
        var cp = new PatrolCheckpoint { Name = "Module Coverage" };
        var modulesHit = latestFindings.Select(f => f.ModuleName).Where(m => !string.IsNullOrEmpty(m)).Distinct().ToList();
        var knownModules = new[] { "Defender", "Firewall", "Update", "Account", "Network", "Encryption", "Browser", "Privacy" };
        var missing = knownModules.Where(m => !modulesHit.Any(h => h != null && h.Contains(m, StringComparison.OrdinalIgnoreCase))).ToList();

        // Modules with no findings could mean they're clean OR not scanned
        cp.Status = PatrolStatus.Pass;
        cp.Summary = $"{modulesHit.Count} modules reported findings in last audit";
        if (modulesHit.Count > 0)
            cp.Details.Add($"Active: {string.Join(", ", modulesHit.Take(6))}");
        report.Checkpoints.Add(cp);
    }

    // ── Checkpoint 5: Audit Frequency ──
    {
        var cp = new PatrolCheckpoint { Name = "Audit Frequency" };
        if (ordered.Count >= 2)
        {
            var lastAuditAge = (DateTimeOffset.Now - ordered.Last().Timestamp).TotalDays;
            var intervals = new List<double>();
            for (int j = 1; j < ordered.Count; j++)
                intervals.Add((ordered[j].Timestamp - ordered[j - 1].Timestamp).TotalDays);
            var avgInterval = intervals.Average();

            if (lastAuditAge <= 7)
            {
                cp.Status = PatrolStatus.Pass;
                cp.Summary = $"Last audit: {lastAuditAge:0.0} days ago (avg interval: {avgInterval:0.0} days)";
            }
            else if (lastAuditAge <= 14)
            {
                cp.Status = PatrolStatus.Warn;
                cp.Summary = $"Last audit: {lastAuditAge:0.0} days ago — consider running more frequently";
                report.RecommendedActions.Add(new PatrolAction
                {
                    Priority = "low",
                    Description = "Audit cadence has slowed. Schedule regular scans.",
                    Command = "winsentinel --schedule-optimize"
                });
            }
            else
            {
                cp.Status = PatrolStatus.Fail;
                cp.Summary = $"Last audit: {lastAuditAge:0.0} days ago — overdue!";
                report.RecommendedActions.Add(new PatrolAction
                {
                    Priority = "high",
                    Description = "No recent audit. Run one now.",
                    Command = "winsentinel --audit"
                });
            }
        }
        else
        {
            cp.Status = PatrolStatus.Warn;
            cp.Summary = "Only 1 audit on record — establish a regular cadence";
        }
        report.Checkpoints.Add(cp);
    }

    // ── Checkpoint 6: Severity Distribution ──
    {
        var cp = new PatrolCheckpoint { Name = "Severity Distribution" };
        var total = latestFindings.Count;
        if (total > 0)
        {
            var critPct = latestFindings.Count(f => string.Equals(f.Severity, "Critical", StringComparison.OrdinalIgnoreCase)) * 100.0 / total;
            var highPct = latestFindings.Count(f => string.Equals(f.Severity, "High", StringComparison.OrdinalIgnoreCase)) * 100.0 / total;
            var medPct = latestFindings.Count(f => string.Equals(f.Severity, "Medium", StringComparison.OrdinalIgnoreCase)) * 100.0 / total;
            var lowPct = latestFindings.Count(f => string.Equals(f.Severity, "Low", StringComparison.OrdinalIgnoreCase)) * 100.0 / total;

            cp.Details.Add($"Critical: {critPct:0}%  High: {highPct:0}%  Medium: {medPct:0}%  Low: {lowPct:0}%");

            if (critPct + highPct > 50)
            {
                cp.Status = PatrolStatus.Fail;
                cp.Summary = $"Severity skews dangerous — {critPct + highPct:0}% are critical/high";
            }
            else if (critPct + highPct > 25)
            {
                cp.Status = PatrolStatus.Warn;
                cp.Summary = $"{critPct + highPct:0}% of findings are critical/high";
            }
            else
            {
                cp.Status = PatrolStatus.Pass;
                cp.Summary = $"Healthy distribution — only {critPct + highPct:0}% critical/high";
            }
        }
        else
        {
            cp.Status = PatrolStatus.Pass;
            cp.Summary = "No findings — clean slate";
        }
        report.Checkpoints.Add(cp);
    }

    // ── Output ──
    if (options.Json || options.PatrolFormat == "json")
    {
        var jsonOptions = new JsonSerializerOptions
        {
            WriteIndented = true,
            Converters = { new JsonStringEnumConverter() }
        };
        var json = JsonSerializer.Serialize(report, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else
    {
        ConsoleFormatter.PrintPatrol(report);
    }

    return report.OverallVerdict == PatrolVerdict.Alert ? 1 : 0;
}

static int HandleRadar(CliOptions options)
{
    using var history = new AuditHistoryService();
    history.EnsureDatabase();

    var runs = history.GetHistory(options.RadarDays);

    if (runs.Count == 0)
    {
        ConsoleFormatter.PrintWarning("No audit data found. Run --audit first.");
        return 1;
    }

    // Latest run for current scores
    var latest = runs.OrderByDescending(r => r.Timestamp).First();
    // Earliest run for comparison
    var earliest = runs.OrderBy(r => r.Timestamp).First();

    var currentModules = latest.ModuleScores
        .OrderBy(m => m.ModuleName)
        .Select(m => (name: m.ModuleName, score: m.Score))
        .ToList();

    var previousLookup = earliest.ModuleScores.ToDictionary(m => m.ModuleName, m => m.Score);
    var previousScores = currentModules
        .Select(m => previousLookup.TryGetValue(m.name, out var s) ? s : (int?)null)
        .ToList();

    if (options.Json)
    {
        var report = new
        {
            command = "radar",
            period = new { days = options.RadarDays, from = earliest.Timestamp, to = latest.Timestamp },
            modules = currentModules.Select((m, i) => new
            {
                name = m.name,
                currentScore = m.score,
                previousScore = previousScores[i],
                delta = previousScores[i].HasValue ? m.score - previousScores[i]!.Value : (int?)null
            }),
            overallScore = latest.OverallScore,
            auditRuns = runs.Count
        };
        var jsonOptions = new JsonSerializerOptions
        {
            WriteIndented = true,
            Converters = { new JsonStringEnumConverter() }
        };
        var json = JsonSerializer.Serialize(report, jsonOptions);
        WriteOutput(json, options.OutputFile);
    }
    else
    {
        ConsoleFormatter.PrintRadar(
            currentModules,
            previousScores,
            latest.OverallScore,
            earliest.Timestamp,
            latest.Timestamp,
            runs.Count,
            options.RadarSize);
    }

    return 0;
}

